// 编辑器与引擎的关系模型
//
//  编辑器进程 (Electron / Node.js)
//  +---------------------------+
//  |  Scene Editor (Canvas)    |
//  |  Inspector (UI Framework) |
//  |  Hierarchy (UI Framework) |
//  |  Asset Manager (FS)       |
//  +---------------------------+
//            |  序列化场景文件 (.scene/.prefab)
//            v
//  引擎运行时进程 (WebGL Canvas)
//  +---------------------------+
//  |  ECS / Scene Graph        |
//  |  Render Pipeline          |
//  |  Animation System         |
//  |  Physics Engine           |
//  +---------------------------+

;
; DSL 脚本示例：NPC 对话和战斗
;
@Main:
  Say(1001, "你好，旅行者！")
  Choose("接受任务", "拒绝", result)
  If(result, 0, @Accept)
  If(result, 1, @Reject)

@Accept:
  Say(1002, "太好了！去消灭 10 只史莱姆吧。")
  AddMission("kill_slime_10")
  EndScript()

@Reject:
  Say(1003, "真遗憾，下次再来吧。")
  EndScript()

// 阻塞操作的工作流程
//
//  脚本执行器                    BlockingResolver                UI 层
//  executeCommand("Say")
//      |
//      +-- handler 调用 api.dialog.show(text)
//      |       |
//      |       +-- resolver.waitFor(DIALOG_CLOSED)
//      |       +-- 显示对话框 UI
//      |       +-- await Promise (挂起)
//      |
//  每帧 update()
//      +-- resolver.tick()
//              |
//              +-- 检查条件是否满足
//              |
//  玩家点击关闭 ->
//      +-- onDialogClosed()
//              +-- resolver.resolveEvent(DIALOG_CLOSED)
//                  +-- Promise resolve
//                      +-- 脚本执行器恢复
//                          +-- 执行下一条命令
